const body = $input.first().json.body || $input.first().json;
const ev = body.event || body;

// Only process error/warn
if (!['error','warn'].includes(ev.severity)) {
  return [{ json: { skip: true, reason: 'info event — ignored', ev } }];
}

// Deduplicate: same reason+name within 5min
const store = $getWorkflowStaticData('global');
if (!store.dedup) store.dedup = {};
const key = `${ev.reason}:${ev.name}:${ev.namespace}`;
const now = Date.now();
if (store.dedup[key] && (now - store.dedup[key]) < 300000) {
  return [{ json: { skip: true, reason: 'deduplicated', key, ev } }];
}
store.dedup[key] = now;

// Cleanup old dedup keys
Object.keys(store.dedup).forEach(k => {
  if (now - store.dedup[k] > 600000) delete store.dedup[k];
});

return [{ json: {
  skip: false,
  severity: ev.severity,
  namespace: ev.namespace || 'workshop',
  kind: ev.kind || 'Pod',
  name: ev.name || '',
  reason: ev.reason || '',
  message: ev.message || '',
  deploy: ev.deploy || ev.name?.split('-').slice(0,-2).join('-') || ev.name,
  node: ev.node || '',
  ts: ev.ts || new Date().toISOString()
}}];

