const agentOut = $input.first().json.output || $input.first().json.error || 'Agent returned no output';
const ev = $('Filter + Dedup').first().json;

// Extract SRE_ACTION if present
const actionMatch = agentOut.match(/SRE_ACTION:\s*(.+)/);
const hasAction = !!actionMatch;
const action = actionMatch ? actionMatch[1].trim() : null;

// Severity icon
const icon = ev.severity === 'error' ? '🔴' : '🟡';

// Build dashboard message
const msg = `${icon} **K8s Event** — \`${ev.reason}\` on \`${ev.deploy}\`\n\n${agentOut}${hasAction ? '\n\n🔐 Awaiting approval — store and approve via TOTP' : ''}`;

return [{ json: {
  message: msg,
  hasAction,
  action,
  severity: ev.severity,
  deploy: ev.deploy,
  namespace: ev.namespace,
  reason: ev.reason,
  agentOutput: agentOut
}}];
